/**
 * Generate Apify firewall config.
 *
 * Data source: https://docs.apify.com/api/v2
 *
 * Apify is a web scraping and automation platform.
 * Uses Bearer token authentication.
 * Token format: opaque string, prefix "apify_api_" observed but not documented.
 */

import { writeOutput } from "./codegen";

const DOCS_URL = "https://docs.apify.com/api/v2";
// Token format not publicly documented; using generic placeholder
const PLACEHOLDER_VALUE = "apify_api_CoffeeSafeLocalCoffeeSafeLocalCoffee0";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Apify API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:apify",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../contracts/firewalls";',
    "",
    "export const apifyFirewall = {",
    '  name: "apify",',
    '  description: "Apify API",',
    "  placeholders: {",
    `    APIFY_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://api.apify.com",',
    "      auth: {",
    "        headers: {",
    '          Authorization: "Bearer ${{ secrets.APIFY_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];

  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Apify firewall config...");
  const ts = generateTypeScript();
  writeOutput("apify", ts, import.meta.dirname);
}
